import { useEffect, useState } from "react";
import API from "../services/api";

function AdminDashboard() {
  const [users, setUsers] = useState([]);
  const [stats, setStats] = useState({ matches: 0, players: 0, teams: 0 });

  useEffect(() => {
    fetchStats();
    // fetchUsers(); // Need an admin route for this
  }, []);

  const fetchStats = async () => {
    try {
      const [m, p, t] = await Promise.all([
        API.get("/matches"),
        API.get("/players"),
        API.get("/teams")
      ]);
      setStats({
        matches: m.data.length,
        players: p.data.length,
        teams: t.data.length
      });
    } catch (err) {
      console.error("Failed to fetch stats");
    }
  };

  return (
    <div className="page">
      <h2>Admin Dashboard</h2>
      <div className="matches-grid">
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>{stats.matches}</h3>
          <p>Total Matches</p>
        </div>
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>{stats.players}</h3>
          <p>Total Players</p>
        </div>
        <div className="card" style={{ textAlign: 'center' }}>
          <h3>{stats.teams}</h3>
          <p>Total Teams</p>
        </div>
      </div>

      <div style={{ marginTop: '30px' }}>
        <h3>Quick Actions</h3>
        <div style={{ display: 'flex', gap: '15px', marginTop: '10px' }}>
          <button className="auth-btn" style={{ width: 'auto' }} onClick={() => window.location.href='/add-match'}>Add Match</button>
          <button className="auth-btn" style={{ width: 'auto' }} onClick={() => window.location.href='/add-player'}>Add Player</button>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
